GUICustomShopGoods = class("GUICustomShopGoods", IGUIWindow)

function GUICustomShopGoods:onLoad()
    self.root:registerEvent(GUIEvent.Click, function()
        SoundUtil.playSound(SoundConfig.selectGoodsStore)
        GUICustomShop:onSelectGoods(self.data)
        ReportUtil.reportCustomShopSelect(self.data.Id)
    end)
    self.ivImage = self:getChildWindowByName("BedWarCustomShopGoods-Image", GUIType.StaticImage)
    self.tvName = self:getChildWindowByName("BedWarCustomShopGoods-Name", GUIType.StaticText)
    self.ivPrice = self:getChildWindowByName("BedWarCustomShopGoods-Price-Icon", GUIType.StaticImage)
    self.tvPrice = self:getChildWindowByName("BedWarCustomShopGoods-Price-Text", GUIType.StaticText)
    self.ivUseIcon = self:getChildWindowByName("BedWarCustomShopGoods-Use-Icon", GUIType.StaticImage)
    self.llLock = self:getChildWindowByName("BedWarCustomShopGoods-Lock-Mask")
    self.ivSelect = self:getChildWindowByName("BedWarCustomShopGoods-Select", GUIType.StaticImage)
    self.llDiscount = self:getChildWindowByName("BedWarCustomShopGoods-Discount", GUIType.Layout)
end

function GUICustomShopGoods:onDataChanged(data)
    self.data = data
    if data.DiscountPrices == data.Price then
        self.llDiscount:SetVisible(false)
        self.tvPrice:SetText(tostring(data.Price))
    else
        self.llDiscount:SetVisible(true)
        local width = self.tvPrice:GetFont():GetTextExtent(tostring(data.Price), 1)
        self.llDiscount:SetWidth({ 0, width })
        self.tvPrice:SetText(tostring(data.Price) .. " " .. tostring(data.DiscountPrices))
    end
    if GUIFontManager:Instance():GetFont("HT14"):GetTextExtent("8888888", 1) > self.root:GetWidth()[2] - 25 then
        self.tvPrice:SetProperty("Font", "HT12")
    else
        self.tvPrice:SetProperty("Font", "HT14")
    end
    self.ivImage:SetImage(data.Image)
    self.tvName:SetText(Lang:getString(data.Name))
    self.ivSelect:SetVisible(GUICustomShop.curSelectGoods == data)
    if data.Time == -1 or data.Time > 0 then
        self.llDiscount:SetVisible(false)
        self.llLock:SetVisible(false)
        self.ivPrice:SetVisible(false)
    else
        self.llLock:SetVisible(true)
        self.ivPrice:SetVisible(true)
    end
    self.ivUseIcon:SetVisible(data.Status == CustomShopGoodsStatus.Equiped)
    if data.Price == -2 then
        self.ivPrice:SetVisible(false)
    end
end